import{_ as e,o as a,c as t,ag as o}from"./chunks/framework.ePeAWSvT.js";const m=JSON.parse('{"title":"COURS : LES AFFECTIONS THYROÏDIENNES","description":"","frontmatter":{},"headers":[],"relativePath":"matieres/sante/cours/affections-thyroïdiennes.md","filePath":"matieres/sante/cours/affections-thyroïdiennes.md"}'),l={name:"matieres/sante/cours/affections-thyroïdiennes.md"};function n(r,i,s,d,h,u){return a(),t("div",null,[...i[0]||(i[0]=[o('<h1 id="cours-les-affections-thyroidiennes" tabindex="-1">COURS : LES AFFECTIONS THYROÏDIENNES <a class="header-anchor" href="#cours-les-affections-thyroidiennes" aria-label="Permalink to &quot;COURS : LES AFFECTIONS THYROÏDIENNES&quot;">​</a></h1><h2 id="_1️⃣-definition" tabindex="-1">1️⃣ Définition <a class="header-anchor" href="#_1️⃣-definition" aria-label="Permalink to &quot;1️⃣ Définition&quot;">​</a></h2><p>Les affections thyroïdiennes sont des <strong>maladies qui touchent la glande thyroïde</strong>, une glande endocrine située à la base du cou.</p><p>👉 La thyroïde produit des hormones importantes :</p><ul><li><strong>T3 (triiodothyronine)</strong></li><li><strong>T4 (thyroxine)</strong></li></ul><p>Ces hormones contrôlent :</p><ul><li>le métabolisme</li><li>la température corporelle</li><li>la fréquence cardiaque</li><li>la croissance</li><li>l’énergie de l’organisme</li></ul><p>La sécrétion des hormones thyroïdiennes est contrôlée par :</p><ul><li><strong>TSH (Thyroid Stimulating Hormone)</strong> produite par l’hypophyse.</li></ul><hr><h2 id="_2️⃣-principales-affections-thyroidiennes" tabindex="-1">2️⃣ Principales affections thyroïdiennes <a class="header-anchor" href="#_2️⃣-principales-affections-thyroidiennes" aria-label="Permalink to &quot;2️⃣ Principales affections thyroïdiennes&quot;">​</a></h2><p>Les principales maladies de la thyroïde sont :</p><ul><li><strong>Hypothyroïdie</strong></li><li><strong>Hyperthyroïdie</strong></li><li><strong>Goitre</strong></li><li><strong>Nodules thyroïdiens</strong></li><li><strong>Cancer de la thyroïde</strong></li></ul><hr><h2 id="_3️⃣-hypothyroidie" tabindex="-1">3️⃣ Hypothyroïdie <a class="header-anchor" href="#_3️⃣-hypothyroidie" aria-label="Permalink to &quot;3️⃣ Hypothyroïdie&quot;">​</a></h2><h3 id="🔹-definition" tabindex="-1">🔹 Définition <a class="header-anchor" href="#🔹-definition" aria-label="Permalink to &quot;🔹 Définition&quot;">​</a></h3><p>L’hypothyroïdie est une <strong>diminution de la production des hormones thyroïdiennes</strong>.</p><p>Cela entraîne un <strong>ralentissement du métabolisme</strong>.</p><hr><h3 id="🔹-causes" tabindex="-1">🔹 Causes <a class="header-anchor" href="#🔹-causes" aria-label="Permalink to &quot;🔹 Causes&quot;">​</a></h3><ul><li>Thyroïdite de Hashimoto (maladie auto-immune)</li><li>Carence en iode</li><li>Ablation de la thyroïde</li><li>Certains médicaments</li><li>Radiothérapie</li></ul><hr><h3 id="🔹-symptomes" tabindex="-1">🔹 Symptômes <a class="header-anchor" href="#🔹-symptomes" aria-label="Permalink to &quot;🔹 Symptômes&quot;">​</a></h3><ul><li>Fatigue</li><li>Prise de poids</li><li>Sensation de froid</li><li>Peau sèche</li><li>Chute des cheveux</li><li>Constipation</li><li>Ralentissement du rythme cardiaque</li><li>Dépression</li></ul><hr><h3 id="🔹-diagnostic" tabindex="-1">🔹 Diagnostic <a class="header-anchor" href="#🔹-diagnostic" aria-label="Permalink to &quot;🔹 Diagnostic&quot;">​</a></h3><p>Le diagnostic repose sur les examens biologiques :</p><ul><li><strong>TSH élevée</strong></li><li><strong>T4 basse</strong></li></ul><hr><h3 id="🔹-traitement" tabindex="-1">🔹 Traitement <a class="header-anchor" href="#🔹-traitement" aria-label="Permalink to &quot;🔹 Traitement&quot;">​</a></h3><ul><li><strong>Hormones thyroïdiennes de substitution (Lévothyroxine)</strong></li></ul><hr><h2 id="_4️⃣-hyperthyroidie" tabindex="-1">4️⃣ Hyperthyroïdie <a class="header-anchor" href="#_4️⃣-hyperthyroidie" aria-label="Permalink to &quot;4️⃣ Hyperthyroïdie&quot;">​</a></h2><h3 id="🔹-definition-1" tabindex="-1">🔹 Définition <a class="header-anchor" href="#🔹-definition-1" aria-label="Permalink to &quot;🔹 Définition&quot;">​</a></h3><p>L’hyperthyroïdie est une <strong>production excessive d’hormones thyroïdiennes</strong>, ce qui provoque une <strong>accélération du métabolisme</strong>.</p><hr><h3 id="🔹-causes-1" tabindex="-1">🔹 Causes <a class="header-anchor" href="#🔹-causes-1" aria-label="Permalink to &quot;🔹 Causes&quot;">​</a></h3><ul><li>Maladie de Basedow</li><li>Nodules thyroïdiens toxiques</li><li>Thyroïdite</li><li>Excès d’iode</li></ul><hr><h3 id="🔹-symptomes-1" tabindex="-1">🔹 Symptômes <a class="header-anchor" href="#🔹-symptomes-1" aria-label="Permalink to &quot;🔹 Symptômes&quot;">​</a></h3><ul><li>Perte de poids</li><li>Nervosité</li><li>Tremblements</li><li>Palpitations</li><li>Intolérance à la chaleur</li><li>Transpiration excessive</li><li>Insomnie</li><li>Diarrhée</li></ul><hr><h3 id="🔹-diagnostic-1" tabindex="-1">🔹 Diagnostic <a class="header-anchor" href="#🔹-diagnostic-1" aria-label="Permalink to &quot;🔹 Diagnostic&quot;">​</a></h3><ul><li><strong>TSH basse</strong></li><li><strong>T3 et T4 élevées</strong></li></ul><hr><h3 id="🔹-traitement-1" tabindex="-1">🔹 Traitement <a class="header-anchor" href="#🔹-traitement-1" aria-label="Permalink to &quot;🔹 Traitement&quot;">​</a></h3><ul><li>Médicaments antithyroïdiens</li><li>Iode radioactif</li><li>Chirurgie dans certains cas</li></ul><hr><h2 id="_5️⃣-goitre" tabindex="-1">5️⃣ Goitre <a class="header-anchor" href="#_5️⃣-goitre" aria-label="Permalink to &quot;5️⃣ Goitre&quot;">​</a></h2><h3 id="🔹-definition-2" tabindex="-1">🔹 Définition <a class="header-anchor" href="#🔹-definition-2" aria-label="Permalink to &quot;🔹 Définition&quot;">​</a></h3><p>Le goitre est une <strong>augmentation du volume de la glande thyroïde</strong>.</p><p>Il peut être :</p><ul><li><strong>diffus</strong></li><li><strong>nodulaire</strong></li></ul><hr><h3 id="🔹-causes-2" tabindex="-1">🔹 Causes <a class="header-anchor" href="#🔹-causes-2" aria-label="Permalink to &quot;🔹 Causes&quot;">​</a></h3><ul><li>Carence en iode</li><li>Maladies auto-immunes</li><li>Nodules thyroïdiens</li><li>Hyperthyroïdie ou hypothyroïdie</li></ul><hr><h2 id="_6️⃣-nodules-thyroidiens" tabindex="-1">6️⃣ Nodules thyroïdiens <a class="header-anchor" href="#_6️⃣-nodules-thyroidiens" aria-label="Permalink to &quot;6️⃣ Nodules thyroïdiens&quot;">​</a></h2><p>Les nodules sont des <strong>petites masses dans la thyroïde</strong>.</p><p>Ils peuvent être :</p><ul><li>bénins (la majorité)</li><li>malins (cancer)</li></ul><p>Examens utilisés :</p><ul><li>Échographie thyroïdienne</li><li>Scintigraphie</li><li>Ponction biopsie</li></ul><hr><h2 id="_7️⃣-cancer-de-la-thyroide" tabindex="-1">7️⃣ Cancer de la thyroïde <a class="header-anchor" href="#_7️⃣-cancer-de-la-thyroide" aria-label="Permalink to &quot;7️⃣ Cancer de la thyroïde&quot;">​</a></h2><p>Le cancer de la thyroïde est généralement <strong>de bon pronostic</strong> lorsqu’il est diagnostiqué tôt.</p><p>Signes possibles :</p><ul><li>nodule au niveau du cou</li><li>difficulté à avaler</li><li>modification de la voix</li></ul><p>Traitement :</p><ul><li>chirurgie (thyroïdectomie)</li><li>iode radioactif</li><li>traitement hormonal substitutif</li></ul><hr><h2 id="_8️⃣-examens-de-la-fonction-thyroidienne" tabindex="-1">8️⃣ Examens de la fonction thyroïdienne <a class="header-anchor" href="#_8️⃣-examens-de-la-fonction-thyroidienne" aria-label="Permalink to &quot;8️⃣ Examens de la fonction thyroïdienne&quot;">​</a></h2><p>Les examens les plus utilisés sont :</p><ul><li><strong>TSH</strong></li><li><strong>T3</strong></li><li><strong>T4</strong></li></ul><p>Examens d’imagerie :</p><ul><li><strong>Échographie thyroïdienne</strong></li><li><strong>Scintigraphie thyroïdienne</strong></li></ul><hr><h2 id="_9️⃣-complications-possibles" tabindex="-1">9️⃣ Complications possibles <a class="header-anchor" href="#_9️⃣-complications-possibles" aria-label="Permalink to &quot;9️⃣ Complications possibles&quot;">​</a></h2><p>Les affections thyroïdiennes peuvent entraîner :</p><ul><li>troubles cardiaques</li><li>infertilité</li><li>troubles métaboliques</li><li>troubles psychologiques</li></ul><hr><h2 id="🔟-role-infirmier-👨‍⚕️👩‍⚕️" tabindex="-1">🔟 Rôle infirmier 👨‍⚕️👩‍⚕️ <a class="header-anchor" href="#🔟-role-infirmier-👨‍⚕️👩‍⚕️" aria-label="Permalink to &quot;🔟 Rôle infirmier 👨‍⚕️👩‍⚕️&quot;">​</a></h2><p>Le rôle infirmier comprend :</p><ul><li>Surveillance des <strong>signes cliniques</strong></li><li>Surveillance des <strong>résultats biologiques</strong></li><li>Administration des traitements</li><li>Éducation du patient sur la maladie</li><li>Surveillance des effets secondaires des médicaments</li><li>Soutien psychologique</li><li>Participation au suivi du patient</li></ul>',84)])])}const p=e(l,[["render",n]]);export{m as __pageData,p as default};
